INSERT INTO 
	t_lecture(
		EDU_NM, CTG1_SEQ,CTG2_SEQ,CTG3_SEQ, OPEN_YN, 
		INSTRCTR_ID, INSTRCTR_NM, IMG_ORG, IMG_RENAME, IMG_USE_YN, EDU_PERIOD_BEGIN, EDU_PERIOD_END, 
		RCEPT_PERIOD_BEGIN, RCEPT_PERIOD_END, RCEPT_PERIOD_YN, PERSONNEL, MIN_PERSONNEL, EXT_PERSONNEL, 
		CLOSE_TP, FEE, GROUP_FEE, FEE_LIMIT, GROUP_COMMENT, CN, POST_NO, ADDR, ADDR_DETAIL, ADDR_ETC,
		ADDR_MEMO, RCEPT_YN, CLOSE_YN, REG_DE, REG_ID, UPD_DE, UPD_ID, ORG_CD, ONLINE_YN, ONLINE_URL, TEL, WAY_COME
		,LCTRE_TYPE,SMS_AUTO,EDU_ETC 
		,TARGETS,PASS_CERT_YN, FB_YN, PRE_EDU_YN ,PASS_IDX
		,PASS_ATT_POINT, PASS_ASG_POINT, PASS_TEST_POINT, PASS_POINT, PRE_EDU_SEQ, FB_IDX, AUTO_PASS_YN 
		,ETC_IEM_YN, INQ_NM, ETC_AGREE_YN, ESSNTL_FILE_YN,SCRTY_YN,SCRTY_PW
		,CANCEL_LIMIT_DT,EDU_YEAR,EDU_TERM
		,TARGET_TP,EDU_TP,RCEPT_CNT_VIEW_YN,RETURN_TP
		,comp_stnd_01,comp_stnd_02,comp_stnd_03,comp_stnd_04,comp_stnd_05
		,meal_fee,dormi_fee ,meal_account,dormi_account,deposit_limit_dt
	)VALUES(
		#{eduNm}, #{ctg1Seq}, #{ctg2Seq}, #{ctg3Seq},  #{openYn}, 
		#{instrctrId}, #{instrctrNm}, #{imgOrg}, #{imgRename}, #{imgUseYn}, #{eduPeriodBegin}, #{eduPeriodEnd}, 
		#{rceptPeriodBegin}, #{rceptPeriodEnd}, #{rceptPeriodYn}, #{personnel}, #{minPersonnel}, #{extPersonnel}, 
		#{closeTp}, #{fee}, #{groupFee}, #{feeLimit}, #{groupComment}, #{cn}, #{postNo}, #{addr}, #{addrDetail}, #{addrEtc}, 
		#{addrMemo}, #{rceptYn}, #{closeYn}, #{regDe}, #{regId}, #{updDe}, #{updId}, #{orgCd}, #{onlineYn}, #{onlineUrl}, #{tel}, #{wayCome}
		,#{lctreType},#{smsAuto},#{eduEtc}
		,#{targets},#{passCertYn},#{fbYn},#{preEduYn}, #{passIdx}
		,#{passAttPoint},#{passAsgPoint},#{passTestPoint},#{passPoint},#{preEduSeq}, #{fbIdx} ,#{autoPassYn}
		,#{etcIemYn},#{inqNm},#{etcAgreeYn},#{essntlFileYn},#{scrtyYn},#{scrtyPw}
		,#{cancelLimitDt},#{eduYear},#{eduTerm}
		,#{targetTp},#{eduTp},#{rceptCntViewYn},#{returnTp}
		,#{compStnd01},#{compStnd02},#{compStnd03},#{compStnd04},#{compStnd05}
		,#{mealFee},#{dormiFee},#{mealAccount},#{dormiAccount},#{depositLimitDt}
	)

mapper.select:
SELECT 
	COUNT(EDU_SEQ) 
FROM 
	t_lecture a
WHERE
	1 = 1 

	AND (EDU_NM LIKE CONCAT('%', #{srchWrd}, '%') or cn LIKE CONCAT('%', #{srchWrd}, '%'))


		AND ctg1_seq = #{srchCtgry}



			AND ctg3_seq = #{srchCtgry3}


			AND (
				ctg2_seq = #{srchCtgry2}
			)



	AND a.ORG_CD = #{srchAgency}


	AND a.ORG_CD in (select org_cd from t_org where sido_cd =#{srchSidoCd})




		and a.ctg1_seq in (select ctgry_seq from t_category_auth where user_id=#{srchRegId})


		and a.reg_id = #{srchRegId}



AND a.EDU_YEAR = #{eduYear}


AND a.EDU_TERM = #{eduTerm}

/** 관리자 > 수업관리 리스트 */
SELECT T.* FROM (
	SELECT 
		a.*, 
		(SELECT COUNT(USER_ID) FROM t_lecture_stdnt WHERE EDU_SEQ = a.EDU_SEQ ) AS RCEPT_CNT,
		0 AS WAIT_CNT
		,(select ctgry_nm from t_category where ctgry_seq=a.ctg1_seq) ctg1_nm
		,(select ctgry_nm from t_category where ctgry_seq=a.ctg2_seq) ctg2_nm
		,(select ctgry_nm from t_category where ctgry_seq=a.ctg3_seq) ctg3_nm
	FROM 
		t_lecture a
	WHERE
		1 = 1 

		AND (EDU_NM LIKE CONCAT('%', #{srchWrd}, '%') or cn LIKE CONCAT('%', #{srchWrd}, '%'))


		AND ctg1_seq = #{srchCtgry}



			AND ctg3_seq = #{srchCtgry3}


			AND (
				ctg2_seq = #{srchCtgry2}
			)



		AND a.ORG_CD = #{srchAgency}


		AND a.ORG_CD in (select org_cd from t_org where sido_cd =#{srchSidoCd})




			and a.ctg1_seq in (select ctgry_seq from t_category_auth where user_id=#{srchRegId})


			and a.reg_id = #{srchRegId}



	AND a.EDU_YEAR = #{eduYear}


	AND a.EDU_TERM = #{eduTerm}


) AS T
ORDER BY T.EDU_PERIOD_BEGIN DESC		

LIMIT #{firstIndex}, #{row}

SELECT *, 0 AS RCEPT_CNT, 0 AS WAIT_CNT ,(select ctgry_nm from t_category where ctgry_seq=a.ctg1_seq) ctg1_nm ,(select ctgry_nm from t_category where ctgry_seq=a.ctg2_seq) ctg2_nm ,(select ctgry_nm from t_category where ctgry_seq=a.ctg3_seq) ctg3_nm FROM t_lecture a WHERE OPEN_YN = 'Y'
and a.ctg1_seq = #{srchCtgry}
ORDER BY edu_period_begin desc, CASE WHEN RCEPT_PERIOD_END >= #{srchDate} THEN 1 ELSE 2 END, CASE WHEN RCEPT_PERIOD_END >= #{srchDate} THEN RCEPT_PERIOD_END END ASC, CASE WHEN RCEPT_PERIOD_END < #{srchDate} THEN RCEPT_PERIOD_END END DESC LIMIT 0, #{viewCnt}

/** 개인교육 리스트 */ SELECT a.*, (SELECT COUNT(*) FROM t_lecture_stdnt T WHERE T.STATE != 3 AND T.EDU_SEQ = a.EDU_SEQ ) AS RCEPT_CNT, 0 AS WAIT_CNT, (SELECT ORG_NM FROM t_org T WHERE T.ORG_CD = a.ORG_CD) AS ORG_NM ,(select ctgry_nm from t_category where ctgry_seq=a.ctg1_seq) ctg1_nm ,(select ctgry_nm from t_category where ctgry_seq=a.ctg2_seq) ctg2_nm ,(select ctgry_nm from t_category where ctgry_seq=a.ctg3_seq) ctg3_nm FROM t_lecture a WHERE a.OPEN_YN = 'Y'
AND (
concat(SUBSTRING(a.EDU_PERIOD_BEGIN, 1, 4),SUBSTRING(a.EDU_PERIOD_BEGIN, 6, 2)) = concat(#{srchYear},#{srchMonth} )
)
and SUBSTRING(a.EDU_PERIOD_BEGIN, 1, 4) = #{srchYear}
AND a.EDU_PERIOD_BEGIN = #{srchDate}
AND a.EDU_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.INSTRCTR_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.ORG_CD IN (SELECT ORG_CD FROM t_org WHERE ORG_NM LIKE CONCAT('%', #{srchWrd}, '%') )
AND (a.EDU_NM LIKE CONCAT('%', #{srchWrd}, '%') )
AND ctg1_seq = #{srchCtgry}
AND ctg3_seq = #{srchCtgry3}
AND ( ctg2_seq = #{srchCtgry2} )
AND a.ORG_CD = #{srchAgency}
AND a.ORG_CD in (select org_cd from t_org where sido_cd =#{srchSidoCd})
AND a.rcept_period_begin <= DATE_FORMAT(NOW(), '%Y%m%d%H%i') AND a.rcept_period_end >= DATE_FORMAT(NOW(), '%Y%m%d%H%i')
ORDER BY
a.EDU_PERIOD_BEGIN DESC, a.EDU_PERIOD_END DESC, a.EDU_NM

SELECT *, 0 AS RCEPT_CNT, 0 AS WAIT_CNT FROM t_lecture a WHERE OPEN_YN = 'Y'
AND ( ( REPLACE(EDU_PERIOD_BEGIN, '-', '') <= REPLACE(#{srchDateBegin}, '-', '') AND REPLACE(EDU_PERIOD_END, '-', '') >= REPLACE(#{srchDateBegin}, '-', '') ) or ( REPLACE(EDU_PERIOD_BEGIN, '-', '') >= REPLACE(#{srchDateBegin}, '-', '') AND REPLACE(EDU_PERIOD_END, '-', '') <= REPLACE(#{srchDateEnd}, '-', '') ) or ( REPLACE(EDU_PERIOD_BEGIN, '-', '') <= REPLACE(#{srchDateEnd}, '-', '') AND REPLACE(EDU_PERIOD_END, '-', '') >= REPLACE(#{srchDateEnd}, '-', '') ) )
AND a.EDU_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.INSTRCTR_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.ORG_CD IN (SELECT ORG_CD FROM t_org WHERE ORG_NM LIKE CONCAT('%', #{srchWrd}, '%') )
AND a.ctg1_seq = #{srchCtgry}
AND a.ctg2_seq = #{srchCtgry2}
AND a.ORG_CD = #{srchAgency}
AND a.ORG_CD in (select org_cd from t_org where sido_cd =#{srchSidoCd})
ORDER BY case when edu_ctgry_seq=49 then 1 when edu_ctgry_seq=50 then 2 when edu_ctgry_seq=51 then 3 else 4 end asc , edu_period_begin desc

SELECT *, 0 AS RCEPT_CNT, 0 AS WAIT_CNT FROM t_lecture WHERE OPEN_YN = 'Y'
AND SUBSTRING(EDU_PERIOD_END, 1, 4) >= #{srchYear}
ORDER BY EDU_PERIOD_BEGIN ASC

/** 관리자 > 신청자카운트 */ SELECT COUNT(*) FROM t_lecture_stdnt a inner join t_lecture_rcept d on a.rcept_seq = d.rcept_seq left join t_user_info b on a.user_id =b.user_id WHERE a.EDU_SEQ = #{eduSeq} and a.state in (1,2,3,4)
AND b.USER_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.MOBILE LIKE CONCAT('%', #{srchWrd}, '%')
AND a.BELONG LIKE CONCAT('%', #{srchWrd}, '%')
AND ( b.login_id LIKE CONCAT('%', #{srchWrd}, '%') or b.user_nm like concat('%', #{srchWrd}, '%') )
AND d.STATE = #{srchRceptState}

/** 관리자 > 신청자목록 */ SELECT T.* ,(SELECT LOGIN_ID FROM t_user_info WHERE USER_ID=T.USER_ID) LOGIN_ID FROM ( SELECT a.edu_seq,a.user_id,a.mobile,a.email,a.state ,d.rcept_seq,d.etc,d.reg_de,d.file_org,d.file_re,d.fee_tp ,d.comp_json,d.school_list_json,d.certif_list_json,d.langua_list_json,d.career_list_json ,d.emp_insr_tp,d.learn_card_tp,d.emp_succ_tp,d.biz_rgs_tp ,b.user_nm,b.birth,b.mf_type ,c.pay_no,c.state pay_state ,c.pay_type ,c.amount pay_fee ,e.fee ,b.user_org_nm ,b.user_grade_nm ,b.tel ,d.use_trans +'' AS use_trans_yn -- 버스탑승여부 ,IF(d.dormi_capa_cnt>0,'Y','N') AS dormi_capa_yn -- 숙소이용여부 ,e.edu_nm FROM t_lecture_stdnt a inner join t_lecture_rcept d on a.rcept_seq = d.rcept_seq left join t_user_info b on a.user_id =b.user_id left join t_pay c on d.pay_no=c.pay_no inner join t_lecture e on a.edu_seq = e.edu_seq WHERE a.EDU_SEQ = #{eduSeq} and a.state in (1,2,3,4)
AND b.USER_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.MOBILE LIKE CONCAT('%', #{srchWrd}, '%')
AND a.BELONG LIKE CONCAT('%', #{srchWrd}, '%')
AND ( b.login_id LIKE CONCAT('%', #{srchWrd}, '%') or b.user_nm like concat('%', #{srchWrd}, '%') )
AND d.STATE = #{srchRceptState}
ORDER BY d.REG_DE desc,a.STATE ASC ) AS T
LIMIT #{firstIndex}, #{row}

