/** 교육 수정 */ UPDATE t_lecture SET EDU_NM = #{eduNm}, ctg1_seq = #{ctg1Seq}, ctg2_seq = #{ctg2Seq}, ctg3_seq = #{ctg3Seq}, OPEN_YN = #{openYn}, INSTRCTR_ID = #{instrctrId}, INSTRCTR_NM = #{instrctrNm}, IMG_ORG = #{imgOrg}, IMG_RENAME = #{imgRename}, IMG_USE_YN = #{imgUseYn}, EDU_PERIOD_BEGIN = #{eduPeriodBegin}, EDU_PERIOD_END = #{eduPeriodEnd}, RCEPT_PERIOD_BEGIN = #{rceptPeriodBegin}, RCEPT_PERIOD_END = #{rceptPeriodEnd}, RCEPT_PERIOD_YN = #{rceptPeriodYn}, PERSONNEL = #{personnel}, MIN_PERSONNEL = #{minPersonnel}, EXT_PERSONNEL = #{extPersonnel}, CLOSE_TP = #{closeTp}, FEE = #{fee}, GROUP_FEE = #{groupFee}, FEE_LIMIT = #{feeLimit}, GROUP_COMMENT = #{groupComment}, CN = #{cn}, POST_NO = #{postNo}, ADDR = #{addr}, ADDR_DETAIL = #{addrDetail}, ADDR_ETC = #{addrEtc}, ADDR_MEMO = #{addrMemo}, UPD_DE = #{updDe}, UPD_ID = #{updId}, ONLINE_YN=#{onlineYn}, ONLINE_URL=#{onlineUrl}, TEL=#{tel}, WAY_COME=#{wayCome}, FB_IDX=#{fbIdx}, PASS_IDX=#{passIdx}, LCTRE_TYPE=#{lctreType}, SMS_AUTO=#{smsAuto}, EDU_ETC=#{eduEtc}, TARGETS=#{targets}, PASS_CERT_YN=#{passCertYn}, FB_YN=#{fbYn}, PRE_EDU_YN= #{preEduYn}, PASS_ATT_POINT=#{passAttPoint}, PASS_ASG_POINT=#{passAsgPoint}, PASS_TEST_POINT=#{passTestPoint}, PASS_POINT=#{passPoint}, PRE_EDU_SEQ=#{preEduSeq}, AUTO_PASS_YN= #{autoPassYn}, ETC_IEM_YN=#{etcIemYn}, INQ_NM=#{inqNm}, ETC_AGREE_YN=#{etcAgreeYn}, SCRTY_YN=#{scrtyYn},
SCRTY_PW=#{scrtyPw},
ESSNTL_FILE_YN=#{essntlFileYn}, CANCEL_LIMIT_DT=#{cancelLimitDt}, EDU_YEAR = #{eduYear}, EDU_TERM = #{eduTerm}, TARGET_TP = #{targetTp}, EDU_TP = #{eduTp}, RCEPT_CNT_VIEW_YN = #{rceptCntViewYn}, RETURN_TP = #{returnTp}, meal_fee = #{mealFee}, dormi_fee = #{dormiFee}, meal_account = #{mealAccount}, dormi_account = #{dormiAccount}, deposit_limit_dt = #{depositLimitDt}, comp_stnd_01 = #{compStnd01}, comp_stnd_02 = #{compStnd02}, comp_stnd_03 = #{compStnd03}, comp_stnd_04 = #{compStnd04}, comp_stnd_05 = #{compStnd05} WHERE EDU_SEQ = #{eduSeq}

