/*진행중*/
SELECT 
	COUNT(*) 
FROM
	t_lecture_rcept 
WHERE 
	EDU_SEQ = #{eduSeq}
	and user_id != #{userId}

SELECT T.* FROM (
	SELECT 
		A.*, 
		@rnum := @rnum + 1 AS RNUM
	FROM 
		t_lecture A, (SELECT @rownum :=0) r
	WHERE
		INSTRCTR_ID = #{userId} 
	ORDER BY A.EDU_PERIOD_BEGIN DESC		
) AS T
LIMIT #{firstIndex}, #{row}

mapper.insert:
INSERT INTO t_lecture_stdnt(
	EDU_SEQ, USER_ID, USER_NM, BELONG, "POSITION", 
	WORKSHOP_SCORE, EXAM_SCORE, PASS_YN, PASS_CERT_ISSUE, PASS_CERT_NUM, 
	COMPL_CERT_ISSUE, COMPL_CERT_NUM, SURVEY_YN ,RCEPT_SEQ, STATE
) VALUES (
	#{eduSeq}, #{userId}, #{userNm}, #{belong}, #{position}, 
	#{workshopScore}, #{examScore}, #{passYn}, #{passCertIssue}, #{passCertNum}, 
	#{complCertIssue}, #{complCertNum}, #{surveyYn}, #{rceptSeq}, #{state}
)

mapper.select:
SELECT ls.*
	 , (select min(state) as state from t_feedback_edu_result where edu_seq = ls.EDU_SEQ and user_id = ls.USER_ID) fe_result_state
  FROM t_lecture_stdnt ls
 WHERE ls.EDU_SEQ = #{eduSeq}
   AND ls.USER_ID = #{userId}

/** 수강자 명단 */ SELECT t.* ,(select count(*) from t_attend_stdnt where edu_seq = t.edu_seq and user_id = t.user_id and att_cd='O') attend_cnt ,(select count(*) from t_test_result where user_id = t.user_id and pass_yn = 'Y' and test_seq in (select test_seq from t_test where edu_seq = t.edu_seq and try_no = 1)) test_pass_cnt ,(select count(*) from t_test_result where user_id = t.user_id and pass_yn = 'Y' and test_seq in (select test_seq from t_test where edu_seq = t.edu_seq and try_no = 2)) test2_pass_cnt FROM ( SELECT a.edu_seq ,a.user_id ,a.mobile ,a.email ,a.belong ,a.position ,a.workshop_score ,a.exam_score ,a.attend_score ,a.pass_yn ,a.pass_cert_issue ,a.pass_cert_num ,a.compl_cert_issue ,a.compl_cert_num ,IF((SELECT ifnull(min(state),1) FROM t_feedback_edu_result WHERE edu_seq = a.EDU_SEQ AND user_id = a.user_id) = 1,'N','Y') AS survey_yn ,a.cert_de ,a.att_cnt ,a.task_file_Org ,a.task_file_rename ,a.rcept_seq ,a.deposit_yn ,c.user_nm,c.birth,c.login_id FROM t_lecture_stdnt a left join t_lecture_rcept b on a.edu_seq=b.edu_seq and a.user_id=b.user_id and a.rcept_seq = b.rcept_seq left join t_user_info c on a.user_id =c.user_id WHERE a.EDU_SEQ = #{eduSeq} and b.EDU_SEQ = #{eduSeq} and a.state = 2
AND c.USER_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.MOBILE LIKE CONCAT('%', #{srchWrd}, '%')
AND a.BELONG LIKE CONCAT('%', #{srchWrd}, '%')
) AS t ORDER BY t.user_nm
LIMIT #{firstIndex}, #{row}

