/** 교육 신청 상태 변경  */
UPDATE
	t_lecture_rcept
SET
	STATE = #{state} 
WHERE
	EDU_SEQ = #{eduSeq} 
	AND USER_ID = #{userId}
	and rcept_seq = #{rceptSeq}

mapper.select:
/** 신청정보 리스트 ,신청일 정렬*/
SELECT * FROM t_lecture_rcept
WHERE
	EDU_SEQ = #{eduSeq} 
order by RECPT_DE

/**강사 > 마이페이지*/ SELECT T.* FROM ( SELECT a.* ,(select ctgry_nm from t_category where ctgry_seq = a.ctg1_seq) ctg1_nm ,(select ctgry_nm from t_category where ctgry_seq = a.ctg2_seq) ctg2_nm ,(select ctgry_nm from t_category where ctgry_seq = a.ctg3_seq) ctg3_nm ,(SELECT COUNT(T.USER_ID) FROM t_lecture_rcept T WHERE T.STATE = 2 AND T.EDU_SEQ = a.EDU_SEQ ) AS RCEPT_CNT ,0 AS WAIT_CNT ,(SELECT ORG_NM FROM t_org T WHERE T.ORG_CD = a.ORG_CD) AS ORG_NM FROM t_lecture a WHERE 1=1 and ( a.INSTRCTR_ID = #{userId} or (a.edu_seq in (select edu_seq from t_lecture_time where check_id=#{userId})) )
AND ( a.edu_period_begin <= #{srchDate} and a.EDU_PERIOD_END >= #{srchDate} and a.CLOSE_YN!='Y' )
AND ( a.edu_period_begin > #{srchDate} and a.CLOSE_YN!='Y' )
AND a.EDU_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.INSTRCTR_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.ctg1_seq = #{srchCtgry}
ORDER BY a.EDU_PERIOD_BEGIN DESC ) AS T LIMIT #{firstIndex}, #{row}

mapper.update:
/** 피드백템플릿 적용하기 */
UPDATE t_lecture
SET FB_IDX=#{fbIdx}
WHERE EDU_SEQ=#{eduSeq}

mapper.select:
/** 설문조사 응시 인원수 */
SELECT COUNT(*) FROM t_lecture_stdnt
WHERE EDU_SEQ = #{eduSeq} and survey_yn='Y'

/** 마이페이지 > 교육리스트, 학생용 */ SELECT T.* FROM ( SELECT a.*, (SELECT COUNT(USER_ID) FROM t_lecture_stdnt WHERE STATE = 1 AND EDU_SEQ = a.EDU_SEQ ) AS RCEPT_CNT, 0 AS WAIT_CNT, (SELECT ORG_NM FROM t_org WHERE ORG_CD = a.ORG_CD) AS ORG_NM ,(select min(start_tm) from t_lecture_time where edu_seq = a.edu_seq) start_tm ,(select max(end_tm) from t_lecture_time where edu_seq = a.edu_seq) end_tm ,(select ctgry_nm from t_category where ctgry_seq = a.ctg1_seq) ctg1_nm ,(select ctgry_nm from t_category where ctgry_seq = a.ctg2_seq) ctg2_nm ,(select ctgry_nm from t_category where ctgry_seq = a.ctg3_seq) ctg3_nm FROM t_lecture a LEFT JOIN (select * from t_lecture_stdnt where user_id=#{userId}) b ON a.EDU_SEQ=b.EDU_SEQ WHERE 1=1
AND a.EDU_SEQ IN (SELECT EDU_SEQ FROM t_lecture_stdnt WHERE USER_ID = #{userId} and state = 2) AND ( #{srchDate} BETWEEN a.EDU_PERIOD_BEGIN and a.EDU_PERIOD_END and a.CLOSE_YN!='Y' )
AND b.state = 1
AND a.EDU_SEQ IN (SELECT EDU_SEQ FROM t_lecture_stdnt WHERE USER_ID = #{userId} and state = 2)
AND a.EDU_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.INSTRCTR_NM LIKE CONCAT('%', #{srchWrd}, '%')
AND a.ctg1_seq = #{srchCtgry}
ORDER BY a.EDU_PERIOD_BEGIN DESC ) AS T LIMIT #{firstIndex}, #{row}

mapper.update:
UPDATE t_lecture
SET 
	IMG_ORG = #{imgOrg}, 
	IMG_RENAME = #{imgRename} 
WHERE
	EDU_SEQ = #{eduSeq}

/** 결제성공 후 상태 변경  */
UPDATE
	t_lecture_rcept
SET
	STATE = #{state} 
WHERE
	EDU_SEQ = #{eduSeq} 
	AND USER_ID = #{userId}
	and PAY_NO=#{payNo}

	/** 취소성공 후 상태 변경  */
UPDATE
	t_lecture_rcept
SET
	STATE = 3 
WHERE
	EDU_SEQ = #{eduSeq} 
	AND USER_ID = #{userId}
	AND rcept_seq = #{rceptSeq}

mapper.select:
/** 강의실 사용현황 */ select a.edu_seq,a.edu_nm ,b.edu_dt ,c.room_nm ,b.start_tm,b.end_tm from t_lecture a inner join t_lecture_time b on a.edu_seq = b.edu_seq left join t_lecture_room c on b.room_seq = c.room_seq where b.room_seq > 0
and b.edu_dt = #{eduDt}
and c.room_seq = #{roomSeq}
and b.edu_dt between concat(#{srchYear},'',#{srchMonth},'01') and concat(#{srchYear},'',#{srchMonth},'31')

mapper.update:
update t_lecture 
set
	instrctr_id = #{instrctrId}
	,instrctr_nm = #{instrctrNm}
where 
	edu_seq = #{eduSeq}

mapper.select:
/** 개인교육신청내역 카운트 */
select count(a.edu_seq) from (
	select a.edu_seq,a.edu_nm, a.edu_period_begin,a.edu_period_end,a.fee,a.cancel_limit_dt,a.edu_year,a.edu_term
	,e.state rcept_state,e.user_id,e.reg_de
	,d.pay_no,d.reg_dt,d.state pay_state,d.pay_type,d.pg_pay_no
	,d.upd_dt upd_dt2
	,d.amount
	,f.user_nm,f.mobile,f.email
	from t_lecture a
	inner join t_lecture_rcept e on a.edu_seq = e.edu_seq
	left join t_pay d on e.rcept_seq = d.rcept_seq and e.user_id = d.user_id and e.pay_no = d.pay_no
	left join t_lecture_stdnt c on e.rcept_seq = c.rcept_seq
	left join t_user_info f on e.user_id=f.user_id
	where 1=1

	and e.user_id = #{userId}


	and e.edu_seq = #{eduSeq}


	and e.state = #{srchState}


	and e.fee_tp = #{srchFeeTp}


	AND a.ctg1_seq = #{srchCtgry}


				AND a.ctg3_seq = #{srchCtgry3}


				AND (
					a.ctg2_seq = #{srchCtgry2}
				)



) a
where 1=1


and date_format(a.reg_de,'%Y%m%d') between #{srchDateBegin} and #{srchDateEnd}



and (
	a.edu_nm like concat('%',#{srchWrd},'%')
	or a.user_nm like concat('%',#{srchWrd},'%')
)



AND a.EDU_YEAR = #{eduYear}


AND a.EDU_TERM = #{eduTerm}


AND a.RCEPT_STATE = #{srchState}

/** 개인교육신청내역 페이징 */
select a.*  
from (
	select a.edu_seq,a.edu_nm, a.edu_period_begin,a.edu_period_end,a.fee,a.cancel_limit_dt,a.edu_year,a.edu_term,a.target_tp
	,d.pay_no,d.reg_dt pay_de,d.state pay_state,d.pay_type,d.pg_pay_no,d.amount
	,e.reg_de,e.rcept_seq ,e.state rcept_state,e.user_id,e.rfnd_state,e.fee_tp,e.comp_json
	,f.user_nm,f.login_id,f.birth,f.mobile,f.email,f.mf_type,f.user_en_nm,f.user_org_nm
	,(select ctgry_nm from t_category where ctgry_seq = a.ctg1_seq) ctg1_nm
	,(select ctgry_nm from t_category where ctgry_seq = a.ctg2_seq) ctg2_nm
	,(select ctgry_nm from t_category where ctgry_seq = a.ctg3_seq) ctg3_nm
	from t_lecture a
	inner join t_lecture_rcept e on a.edu_seq = e.edu_seq
	left join t_pay d on e.rcept_seq = d.rcept_seq and e.user_id = d.user_id and e.pay_no = d.pay_no
	left join t_lecture_stdnt c on e.rcept_seq = c.rcept_seq
	left join t_user_info f on e.user_id=f.user_id
	where 1=1

	and e.user_id = #{userId}


	and e.edu_seq = #{eduSeq}


	and e.state = #{srchState}


	and e.fee_tp = #{srchFeeTp}


	AND a.ctg1_seq = #{srchCtgry}


				AND a.ctg3_seq = #{srchCtgry3}


				AND (
					a.ctg2_seq = #{srchCtgry2}
				)



) a
where 1=1


and date_format(a.reg_de,'%Y%m%d') between #{srchDateBegin} and #{srchDateEnd}



and (
	a.edu_nm like concat('%',#{srchWrd},'%')
	or a.user_nm like concat('%',#{srchWrd},'%')
)



AND a.EDU_YEAR = #{eduYear}


AND a.EDU_TERM = #{eduTerm}


AND a.RCEPT_STATE = #{srchState}

order by 

a.REG_DE DESC,

a.REG_DE DESC,
a.EDU_NM,a.USER_NM,a.PAY_DE DESC

LIMIT #{firstIndex}, #{row}

/** 과목수료정보 */
select a.edu_seq,a.user_id ,a.user_nm 
,b.sub_nm,b.sub_seq,b.compl_idx,b.pass_idx
,c.pass_cert_num ,c.pass_cert_de,c.pass_state ,c.compl_cert_num ,c.compl_cert_de ,c.compl_state 
,(select max(concat(edu_dt,end_tm)) from t_lecture_time where edu_seq = a.edu_seq and sub_seq = b.sub_seq) end_de_str
from t_lecture_stdnt a 
left join (select * from t_lecture_subject where sub_seq in (select sub_seq from t_lecture_time where edu_seq = #{eduSeq} )) b on 1=1 
left join t_lecture_subject_stdnt c on a.edu_seq = c.edu_seq and a.user_id = c.user_id and b.sub_seq = c.sub_seq 
where a.edu_seq = #{eduSeq} 

	and a.user_id=#{userId}


	and b.sub_seq = #{subSeq}

order by a.user_id ,b.sub_seq
